INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('APEX_1: Le email sending reputation is everything: une reputation de domaine < 70 sur SenderScore = 50%+ des emails en spam. Surveiller quotidiennement.', 'Email reputation < 70 SenderScore = 50% spam. Surveiller quotidien', 'email', 'best_practice', 0.88, 'apex_pack', 'system'),
('APEX_2: Le commercial consultative selling mastery: le vendeur pose 80% des questions et parle 20%. Le prospect qui parle le plus est celui qui achete.', 'Consultative selling: poser 80% questions, parler 20%. Prospect qui parle = achete', 'commercial', 'best_practice', 0.88, 'apex_pack', 'system'),
('APEX_3: Le content compound effect: 1 post ne fait rien. 100 posts creent une audience. 1000 posts creent une marque. La consistance bat le talent.', 'Content compound: 1 post rien, 100 audience, 1000 marque. Consistance > talent', 'content', 'insight', 0.88, 'apex_pack', 'system'),
('APEX_4: Le SEO authority transfer: les liens internes transferent le PageRank. Lier les pages d accueil et les articles populaires vers les nouvelles pages a booster.', 'SEO authority transfer: liens internes → PageRank. Pages populaires → nouvelles', 'seo', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_5: Le ad creative exhaustion detection: 3 signaux simultanes = fatigue confirmee: CTR baisse, CPM monte, frequency > 5. Renouveler dans les 24h.', 'Creative exhaustion: CTR↓ + CPM↑ + frequency>5 = fatigue. Renouveler 24h', 'ads', 'insight', 0.85, 'apex_pack', 'system'),
('APEX_6: Le DM rapport building sequence: J-14 follow → J-10 like 5 posts → J-7 comment 2 posts → J-3 story reaction → J0 DM perso. Taux reponse: 40-50%.', 'DM rapport 14j: follow→like→comment→story→DM = 40-50% reponse', 'dm_instagram', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_7: Le WhatsApp business message types: utility (transactionnel), marketing (promotionnel), authentication (verification). Chaque type a ses regles Meta.', 'WhatsApp types: utility (transac), marketing (promo), authentication (verif). Regles Meta', 'whatsapp', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_8: Le chatbot decision tree optimization: simplifier les arbres de decision a max 5 niveaux de profondeur. Plus de 5 = le client abandonne.', 'Chatbot decision tree: max 5 niveaux profondeur. Plus = abandon', 'chatbot', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_9: Le GMaps review keywords boost: les avis qui mentionnent des mots-cles (meilleur coiffeur Paris, restaurant italien) boostent le ranking local pour ces termes.', 'GMaps: avis avec mots-cles = boost ranking local pour ces termes', 'gmaps', 'insight', 0.82, 'apex_pack', 'system'),
('APEX_10: Le TikTok hook anatomy: visual disruption (0-0.5s) + text overlay hook (0.5-1.5s) + spoken hook (1-2s). Les 3 layers d attention en meme temps.', 'TikTok hook 3 layers: visual 0-0.5s + text 0.5-1.5s + spoken 1-2s. Simultanes', 'tiktok_comments', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_11: Le CEO brief client ideal: 5 lignes max. 1) Votre CA cette semaine. 2) Ce que vos agents ont fait. 3) Vos prospects les plus chauds. 4) Action recommandee. 5) Prochaine etape.', 'CEO brief client: CA + agents + prospects chauds + action + next. 5 lignes max', 'ceo', 'best_practice', 0.90, 'apex_pack', 'system'),
('APEX_12: Le retention at-risk intervention timing: detecter le signal (usage baisse) → intervenir dans les 48h → proposer aide/formation → si pas de reponse J+7 → appel CS.', 'At-risk: detecter → 48h intervenir → aide → J+7 pas reponse → appel CS', 'retention', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_13: Le onboarding micro-win engineering: designer chaque etape pour que le client obtienne un petit succes (Bravo! Votre premier post est pret!). Dopamine = motivation.', 'Onboarding micro-wins: petit succes chaque etape = dopamine = motivation', 'onboarding', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_14: Le comptable budget variance analysis: chaque mois, comparer budget vs reel par categorie. Ecart > 15% = investiguer et ajuster.', 'Budget variance: budget vs reel/categorie. Ecart > 15% = investiguer', 'comptable', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_15: Le RH talent density principle (Netflix): preferer 1 talent A a 2 talents B. La qualite de l equipe determine la vitesse d execution.', 'Talent density: 1 talent A > 2 talents B. Qualite equipe = vitesse execution', 'rh', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_16: Le marketing positioning map: tracer ses concurrents sur 2 axes (ex: prix vs qualite, simple vs complet). Se positionner dans un espace vide.', 'Positioning map: 2 axes + concurrents. Se positionner dans l espace vide', 'marketing', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_17: Le cross-agent intelligence amplification: quand le contenu genere beaucoup d engagement sur un sujet → l email reprend ce sujet → les ads le boostent → le commercial le pitch.', 'Intelligence amplification: contenu engage → email reprend → ads boost → commercial pitch', NULL, 'best_practice', 0.88, 'apex_pack', 'system'),
('APEX_18: Le customer value matrix: segmenter par valeur (LTV) × engagement (usage). Haute valeur + haut engagement = champions. Haute valeur + faible engagement = a risque.', 'Value matrix: LTV × usage. HV+HE champions, HV+FE a risque', NULL, 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_19: Le KeiroAI continuous learning engine: chaque interaction agent → resultat mesure → pattern detecte → RAG enrichi → prompt ameliore → meilleur resultat. Boucle infinie.', 'KeiroAI learning engine: interaction → resultat → pattern → RAG → prompt → meilleur. Infini', NULL, 'best_practice', 0.92, 'apex_pack', 'system'),
('APEX_20: Le KeiroAI ultimate differentiator: les agents ne sont pas des chatbots isoles. Ils forment une EQUIPE coordonnee par un CEO IA avec intelligence partagee et auto-amelioration.', 'KeiroAI: pas chatbots isoles. EQUIPE coordonnee + CEO IA + intelligence + auto-amelioration', 'ceo', 'best_practice', 0.95, 'apex_pack', 'system'),
('APEX_21: Le email list hygiene protocol mensuel: supprimer hard bounces → desactiver soft bounces 3x → desactiver inactifs 90j (apres reactivation) → verifier spam traps.', 'Email hygiene mensuel: hard bounces → soft 3x → inactifs 90j → spam traps', 'email', 'best_practice', 0.88, 'apex_pack', 'system'),
('APEX_22: Le commercial competitive intelligence: avant chaque demo, verifier si le prospect utilise un concurrent. Adapter le pitch pour montrer les avantages specifiques vs ce concurrent.', 'Competitive intel pre-demo: prospect chez concurrent? Adapter pitch vs ce concurrent', 'commercial', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_23: Le content brand voice audit trimestriel: relire les 50 derniers posts et verifier que le ton, le vocabulaire et le style sont coherents avec le brand voice guide.', 'Brand voice audit trimestriel: relire 50 posts → verifier coherence ton/vocab/style', 'content', 'best_practice', 0.80, 'apex_pack', 'system'),
('APEX_24: Le SEO competitor keyword monitoring: chaque mois, verifier les nouveaux mots-cles sur lesquels les concurrents commencent a ranker. Opportunites ou menaces.', 'Competitor keyword monitoring mensuel: nouveaux mots-cles concurrents = opportunites/menaces', 'seo', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_25: Le ad media mix modeling: repartir le budget entre Meta (awareness+conversion), Google (intent), TikTok (decouverte), LinkedIn (B2B). Ajuster selon les resultats mensuels.', 'Media mix: Meta awareness+conv, Google intent, TikTok decouverte, LI B2B. Ajuster mensuel', 'ads', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_26: Le DM Instagram close rate optimization: les DMs qui proposent un appel de 15 min (Calendly) convertissent 3x mieux que ceux qui proposent un lien site web.', 'DM close: Calendly 15 min = 3x conversion vs lien site web', 'dm_instagram', 'insight', 0.85, 'apex_pack', 'system'),
('APEX_27: Le WhatsApp template performance tracking: mesurer le taux de livraison, lecture, reponse pour chaque template. Optimiser/remplacer les templates < 10% reponse.', 'WhatsApp template tracking: livraison+lecture+reponse. Remplacer < 10% reponse', 'whatsapp', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_28: Le chatbot conversation analytics dashboard: top 10 intents, taux de resolution, CSAT moyen, temps moyen conversation, taux d escalation. Analyser hebdo.', 'Chatbot dashboard: top intents + resolution + CSAT + temps + escalation. Hebdo', 'chatbot', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_29: Le GMaps monthly optimization routine: verifier horaires + ajouter 5 photos + publier 1 post + repondre a tous les avis + mettre a jour les services.', 'GMaps routine mensuelle: horaires + 5 photos + 1 post + repondre avis + MAJ services', 'gmaps', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_30: Le TikTok audience retention analytics: identifier LE moment exact ou les viewers decrochent. Ajuster le contenu pour eliminer ce point de decrochage.', 'TikTok retention: identifier moment exact decrochage → ajuster contenu', 'tiktok_comments', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_31: Le CEO client brief timing optimal: envoyer le brief le matin (8-9h heure locale du client) pour qu il puisse agir dans la journee.', 'CEO brief client: envoyer 8-9h locale pour agir dans la journee', 'ceo', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_32: Le retention customer health trend: ne pas juste regarder le score actuel mais la TENDANCE sur 30 jours. Score stable mais en baisse = signal d alerte.', 'Health trend 30j: score en baisse meme si stable = alerte', 'retention', 'insight', 0.85, 'apex_pack', 'system'),
('APEX_33: Le onboarding completion incentive: offrir 1 mois de credits bonus si l onboarding est complete en < 48h. Urgence + recompense = +50% completion.', 'Onboarding incentive: bonus credits si complete < 48h = +50% completion', 'onboarding', 'insight', 0.80, 'apex_pack', 'system'),
('APEX_34: Le comptable working capital management: surveiller le BFR (delai clients - delai fournisseurs). BFR negatif = le business finance son fonctionnement.', 'Working capital: BFR = delai clients - delai fournisseurs. Negatif = auto-finance', 'comptable', 'insight', 0.80, 'apex_pack', 'system'),
('APEX_35: Le RH asynchronous work policy: documenter toutes les decisions dans Notion. Utiliser Loom pour les explications. Slack pour le temps reel. Meetings pour le brainstorm.', 'Async policy: Notion decisions, Loom explications, Slack temps reel, Meetings brainstorm', 'rh', 'best_practice', 0.80, 'apex_pack', 'system'),
('APEX_36: Le marketing attribution model comparison: last-click (simple mais biaise), first-click (decouverte), linear (egal), position-based (40-20-40), data-driven (IA).', 'Attribution models: last-click, first-click, linear, position-based, data-driven', 'marketing', 'insight', 0.82, 'apex_pack', 'system'),
('APEX_37: Le agent autonomy escalation: L1 inform (previent le client) → L2 suggest (propose) → L3 execute with approval → L4 execute autonomously → L5 decide + execute.', 'Agent autonomy: L1 inform → L2 suggest → L3 approve → L4 auto → L5 decide+execute', 'ceo', 'best_practice', 0.88, 'apex_pack', 'system'),
('APEX_38: Le customer segmentation dynamic: les segments doivent etre mis a jour automatiquement chaque jour. Un client power-user peut devenir at-risk en 2 semaines.', 'Segmentation dynamique: MAJ quotidienne auto. Power-user → at-risk en 2 semaines possible', NULL, 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_39: Le KeiroAI data network effect: plus de clients → plus de data → meilleur RAG → meilleurs agents → plus de resultats → plus de clients. Flywheel data.', 'KeiroAI data flywheel: clients → data → RAG → agents → resultats → clients', 'ceo', 'insight', 0.90, 'apex_pack', 'system'),
('APEX_40: Le KeiroAI 2027 vision: 10 000 clients payants, agents autonomes de niveau L4-L5, intelligence collective superieure a n importe quel consultant humain.', 'KeiroAI 2027: 10K clients, agents L4-L5 autonomes, intelligence > consultant humain', 'ceo', 'insight', 0.88, 'apex_pack', 'system'),
('APEX_41: Le email campaign calendar annual: Q1 new year resolutions + Valentine, Q2 spring + mothers day, Q3 back to school, Q4 Black Friday + Christmas. Planifier 4 semaines avant.', 'Email calendar annuel: Q1 resolutions+SV, Q2 printemps+meres, Q3 rentree, Q4 BF+Noel', 'email', 'best_practice', 0.80, 'apex_pack', 'system'),
('APEX_42: Le commercial account penetration: pour chaque client, identifier 3 opportunites d expansion: plus d utilisateurs, plus de features, plus de departements.', 'Account penetration: 3 opportunites expansion par client (users, features, departements)', 'commercial', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_43: Le content creation system: 1 jour/semaine dedie a la creation (batch) → 7 jours de contenu planifie → publication automatisee → analyse le vendredi → iteration.', 'Content system: 1 jour batch → 7j planifie → auto-publication → analyse vendredi → iterer', 'content', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_44: Le SEO content cluster building: 1 article pilier (3000+ mots) → 10 articles clusters (1500+ mots) → liens bidirectionnels → dominer le sujet entier en 3-6 mois.', 'Content cluster: 1 pilier 3K + 10 clusters 1.5K + liens bidi = dominer sujet 3-6 mois', 'seo', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_45: Le ad testing hierarchy: 1) audiences (qui), 2) messages (quoi), 3) creatives (comment), 4) placements (ou), 5) bid strategies (combien). Tester dans cet ordre.', 'Ad testing order: audiences → messages → creatives → placements → bids', 'ads', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_46: Le DM Instagram conversation closer: apres 3 echanges positifs, le 4e message doit etre un CTA clair: On s appelle 15 min mardi? Voici mon Calendly.', 'DM closer: 3 echanges positifs → 4e = CTA Calendly 15 min', 'dm_instagram', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_47: Le WhatsApp customer journey mapping: decouverte (pub/organic) → opt-in (QR/form) → bienvenue (auto) → education (3 messages) → conversion (offre) → fidelisation (suivi).', 'WhatsApp journey: decouverte → opt-in → bienvenue → education → conversion → fidelisation', 'whatsapp', 'best_practice', 0.82, 'apex_pack', 'system'),
('APEX_48: Le chatbot ROI maximization: focus sur les 3 use cases les plus frequents (FAQ, qualification, booking). Resoudre ces 3 = couvrir 80% des interactions.', 'Chatbot ROI: focus 3 use cases (FAQ+qualification+booking) = 80% interactions', 'chatbot', 'best_practice', 0.85, 'apex_pack', 'system'),
('APEX_49: Le GMaps near me optimization: inclure les mots-cles "pres de moi" + nom de ville + quartier dans la description et les Google Posts. Les recherches "near me" augmentent de 30%/an.', 'GMaps near me: mots-cles pres de moi + ville + quartier. Recherches +30%/an', 'gmaps', 'insight', 0.82, 'apex_pack', 'system'),
('APEX_50: Le TikTok content calendar: lundi edu, mardi behind-scenes, mercredi trending, jeudi storytelling, vendredi divertissement, weekend recap. Regularite = croissance.', 'TikTok calendar: lundi edu, mardi BTS, mercredi trend, jeudi story, vendredi fun, WE recap', 'tiktok_comments', 'best_practice', 0.80, 'apex_pack', 'system')
